/**
 * SlsStyleGuideAttributesPatchRequest
 *
 * Body for the attributes PATCH endpoints.
 *
 * Merge semantics: keys present in the body are merged in, keys
 * absent are left untouched. Explicit `null` removes a key. Unknown
 * keys 422 via `extra="forbid"`. Per-key validation runs before the
 * merge (see endpoint bodies).
 *
 * Read `payload.model_fields_set` to distinguish "key omitted" from
 * "key explicit-null". The defaulted `None` on the field is the
 * omitted shape; only act on the value when the key name is in
 * `model_fields_set`.
 */
export type SlsStyleGuideAttributesPatchRequest = {
  /**
   * Default Style Guide Target Id
   *
   * Target to pin as the subject's default style guide. Pass `null` to clear. Omit the key to leave the existing value untouched.
   */
  default_style_guide_target_id?: string | null;
};

/**
 * SlsStyleGuideGrantResponseItem
 *
 * One row in the GET response.
 *
 * `target_id` is the SLS-owned id; `is_default` is True when the
 * subject's `attributes.default_style_guide_target_id` matches.
 */
export type SlsStyleGuideGrantResponseItem = {
  /**
   * Target Id
   */
  target_id: string;
  /**
   * Is Default
   */
  is_default: boolean;
};

/**
 * SlsStyleGuideGrantsRequest
 *
 * Body for the POST grant endpoints.
 *
 * Per-target writes are idempotent so retries are safe. `default_target_id`,
 * if provided, must appear in `target_ids` OR already be held by the
 * subject; the endpoint will fail validation otherwise. To pin only a
 * default without granting new visibilities, pass `target_ids=[]`.
 */
export type SlsStyleGuideGrantsRequest = {
  /**
   * Target Ids
   *
   * SLS target_ids to grant visibility on. May be empty.
   */
  target_ids?: Array<string>;
  /**
   * Default Target Id
   *
   * If set, pin this target as the subject's default in the same transaction as the grants. Must be visible to the subject (either being granted in this call or already granted).
   */
  default_target_id?: string | null;
};

/**
 * SlsStyleGuideGrantsResponse
 */
export type SlsStyleGuideGrantsResponse = {
  /**
   * Target Ids
   */
  target_ids: Array<SlsStyleGuideGrantResponseItem>;
  /**
   * Default Target Id
   */
  default_target_id?: string | null;
};

/**
 * SsoAttributeConfig
 *
 * One claim-mapping rule. Multiple of these per connection compose the
 * full extraction policy.
 */
export type SsoAttributeConfig = {
  /**
   * Attribute
   *
   * JWT claim name carrying group identifiers for this attribute.
   */
  attribute: string;
  /**
   * Claim Format
   *
   * Shape of the claim value: array_strings | dn_strings | comma_separated.
   */
  claim_format: "array_strings" | "dn_strings" | "comma_separated";
  /**
   * Prefix Filter
   *
   * Optional prefix the IDP-emitted group string must start with to be kept; the prefix is stripped from the canonical identifier.
   */
  prefix_filter?: string | null;
};

/**
 * SsoConfig
 *
 * Per-connection SSO group-mapping config.
 *
 * An empty config (`attributes=[]`, no primary, no ignores) is the valid
 * initial state. Field names form the contract with the post-login Action
 * and must stay stable.
 */
export type SsoConfig = {
  /**
   * Attributes
   *
   * Ordered list of attribute mappings.
   */
  attributes?: Array<SsoAttributeConfig>;
  /**
   * Ignore Groups
   *
   * Per-connection list of canonical (post-prefix-strip) group identifiers to drop from the extracted groups set.
   */
  ignore_groups?: Array<string>;
  /**
   * Primary Group Attribute
   *
   * Optional. Names one of `attributes[].attribute`; the first value the IDP emits for that attribute becomes the user's primary group.
   */
  primary_group_attribute?: string | null;
};

/**
 * SsoConnection
 *
 * Public projection of an Auth0 SSO connection in the caller's org.
 */
export type SsoConnection = {
  /**
   * Id
   *
   * Auth0 connection ID
   */
  id: string;
  /**
   * Name
   *
   * Connection name, e.g. 'acme-engineering-sso-a1b2c3d4'.
   */
  name: string;
  /**
   * Strategy
   *
   * Normalized strategy ('saml' or 'oidc').
   */
  strategy: "saml" | "oidc";
  /**
   * Assign Membership On Login
   *
   * Whether new users authenticating via this connection are auto-added as org members. Auth0 has no top-level connection `enabled` flag; this is the closest signal — admin can flip it in Auth0 to suspend JIT membership without deleting the connection.
   */
  assign_membership_on_login: boolean;
  /**
   * Idp Entity Id
   *
   * Cached SAML entityId / OIDC issuer for this connection, or `null` if not yet populated. Lazily fetched and cached on the first list-endpoint call after the connection appears.
   */
  idp_entity_id?: string | null;
  /**
   * Display Name
   *
   * Friendly name the admin gave the connection at create time. Lazily fetched and cached alongside `idp_entity_id`. Falls back to the technical `name` (slugified) when this hasn't been populated for older connections.
   */
  display_name?: string | null;
  /**
   * Mapping Configured
   *
   * True if the connection has at least one claim-mapping attribute configured.
   */
  mapping_configured: boolean;
  /**
   * Domain Aliases Sync Failed At
   *
   * Set when the last Auth0 domain-alias sync for this connection failed. Null means either no sync has been attempted or the last sync succeeded.
   */
  domain_aliases_sync_failed_at?: string | null;
};

/**
 * SsoConnectionsResponse
 */
export type SsoConnectionsResponse = {
  /**
   * Connections
   *
   * Every SSO connection currently enabled for the caller's org. Empty list means no SSO is configured. An org may have multiple connections per strategy.
   */
  connections?: Array<SsoConnection>;
};

